template <int N, class F>
double benchmark(F&& fn) {
  double acc = 0.0;
  for (int i = 0; i < N; ++i) acc += fn();
  return acc / static_cast<double>(N);
}

template <typename T>
inline bool is_equal(const T& a, const T& b) {
  return a == b;
}

inline bool is_equal(const Half2& a, const Half2& b) {
  return a.x == b.x && a.y == b.y;
}

template <typename T>
double run_kernel(T* g_data,
                  long size,
                  int current_compute_iterations,
                  unsigned int elements_per_wi,
                  unsigned int fusion_degree,
                  bool block_strided,
                  std::size_t workgroupsize) {
  (void)workgroupsize;
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int blockSize = static_cast<int>(workgroupsize);

  auto t0 = std::chrono::high_resolution_clock::now();

  volatile double sink = 0.0;

#pragma omp parallel for schedule(static) reduction(+ : sink)
  for (long gid = 0; gid < compute_grid_size; ++gid) {
    const int stride =
        block_strided ? blockSize : static_cast<int>(compute_grid_size);
    const long idx =
        block_strided
            ? (gid / blockSize) * blockSize * static_cast<long>(elements_per_wi) +
                  (gid % blockSize)
            : gid;
    const long big_stride =
        compute_grid_size * static_cast<long>(elements_per_wi);

    std::array<T, 8> tmps{};
    for (unsigned int k = 0; k < fusion_degree; ++k) {
      for (unsigned int j = 0; j < elements_per_wi; ++j) {
        tmps[j] = g_data[idx + static_cast<long>(j) * stride +
                         static_cast<long>(k) * big_stride];
        for (int i = 0; i < current_compute_iterations; ++i) {
          tmps[j] = tmps[j] * tmps[j] + static_cast<T>(1);
        }
      }

      T sum = static_cast<T>(0);
      for (unsigned int j = 0; j < elements_per_wi; j += 2) {
        sum += tmps[j] * tmps[j + 1];
      }

      if (is_equal(sum, static_cast<T>(-1))) {
        g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
      sink += static_cast<double>(j = 0, 1);  // keeps loop side-effects alive
      sink += static_cast<double>(sum != static_cast<T>(-1));
    }
  }

  auto t1 = std::chrono::high_resolution_clock::now();
  (void)sink;
  std::chrono::duration<double, std::milli> ms = t1 - t0;
  return ms.count();
}

double run_kernel_int(std::int32_t* g_data,
                      long size,
                      int current_compute_iterations,
                      unsigned int elements_per_wi,
                      unsigned int fusion_degree,
                      bool block_strided,
                      std::size_t workgroupsize) {
